async def github_webhook(
    request: Request,
    x_hub_signature_256: str = Header(None),
    x_github_event: str = Header(None),
):
    payload_bytes = await request.body()

    if not _verify_github_signature(payload_bytes, x_hub_signature_256):
        raise HTTPException(status_code=401, detail="Invalid signature")

    if x_github_event != "push":
        return {"status": "ignored", "event": x_github_event}

    payload = await request.json()

    repo_url = payload.get("repository", {}).get("html_url")
    if not repo_url:
        raise HTTPException(status_code=400, detail="No repository URL in payload")

    async with async_session() as session:
        repo = await session.scalar(
            select(Repo).where(Repo.github_url == repo_url)
        )
        if not repo:
            raise HTTPException(status_code=404, detail=f"Repo not tracked: {repo_url}")
        repo_id = str(repo.id)

    # Enqueue with dramatiq — identical mental model to RQ, different syntax
    from app.workers.ingestion_worker import run_process_push_event
    run_process_push_event.send(repo_id, payload)

    return {"status": "queued", "repo_id": repo_id}

class ConnectionManager:
    def __init__(self):
        self._connections: dict[str, list[WebSocket]] = defaultdict(list)

    async def connect(self, repo_id: str, websocket: WebSocket):
        await websocket.accept()
        self._connections[repo_id].append(websocket)

    def disconnect(self, repo_id: str, websocket: WebSocket):
        self._connections[repo_id].remove(websocket)

    async def broadcast(self, repo_id: str, message: dict):
        dead = []
        for ws in self._connections[repo_id]:
            try:
                await ws.send_json(message)
            except Exception:
                dead.append(ws)
        for ws in dead:
            self._connections[repo_id].remove(ws)

    def publish(self, repo_id: str, message: dict):
        """
        Called from the worker process — publishes to Redis channel.
        The FastAPI process subscribes and forwards to WebSocket clients.
        """
        _redis.publish(f"devpulse:{repo_id}", json.dumps(message))

